import ImageTracer from "imagetracerjs";

console.log("[ui.ts] UI loaded (step 7 - with SVG parser)");

// 语言配置
const i18n = {
  en: {
    sourceImage: "Source Image",
    noImage: "No image selected",
    svgPreview: "SVG Preview",
    convertParams: "Conversion Parameters",
    presetDefault: "Default",
    presetCurvy: "Curvy",
    presetSharp: "Sharp",
    presetDetailed: "Detailed",
    simplifyCurves: "Simplify Curves",
    simplifyCurvesHint: "Smaller = more detail, larger = smoother",
    ignorePaths: "Ignore Paths",
    ignorePathsHint: "Smaller = more detail, larger = simpler",
    enhanceCorners: "Enhance Corners",
    enhanceCornersHint: "Detect and enhance right-angle edges",
    waitingSelection: "Waiting for image selection...",
    converting: "Converting to SVG...",
    conversionSuccess: "Conversion successful!",
    conversionError: "Conversion error:",
    copySvg: "Copy SVG",
    exportSvg: "Export SVG",
    pleaseConvertFirst: "Please convert to SVG first",
    svgCopied: "SVG copied to clipboard, paste directly to Figma!",
    copyError: "Copy error:",
    svgExported: "SVG exported!",
    exportError: "Export error:",
    selectionRead: "Selection read:",
    unknownNode: "Unknown node"
  },
  zh: {
    sourceImage: "源图像",
    noImage: "未选中图像",
    svgPreview: "SVG 预览",
    convertParams: "转换参数",
    presetDefault: "默认",
    presetCurvy: "平滑",
    presetSharp: "锐利",
    presetDetailed: "细致",
    simplifyCurves: "简化曲线",
    simplifyCurvesHint: "越小曲线越细致，越大曲线越平滑",
    ignorePaths: "忽略路径",
    ignorePathsHint: "越少细节越多，越大图形越简洁",
    enhanceCorners: "增强直角",
    enhanceCornersHint: "检测并增强直角边缘，让图形更锐利",
    waitingSelection: "正在等待选中图像...",
    converting: "正在转换为 SVG...",
    conversionSuccess: "转换成功！",
    conversionError: "转换失败: ",
    copySvg: "复制SVG",
    exportSvg: "导出SVG",
    pleaseConvertFirst: "请先转换为 SVG",
    svgCopied: "SVG 源码已复制到剪贴板，可直接粘贴至Figma！",
    copyError: "复制失败: ",
    svgExported: "SVG 文件已导出！",
    exportError: "导出失败: ",
    selectionRead: "选择已读取: ",
    unknownNode: "未知节点"
  }
};

// 当前语言，默认为英文
let currentLang = "en";

// 翻译函数
function t(key: string): string {
  return i18n[currentLang as keyof typeof i18n][key as keyof typeof i18n.en] || key;
}

// 更新页面语言
function updateLanguage(lang: string) {
  currentLang = lang;
  
  // 更新HTML的lang属性
  document.documentElement.lang = lang === "zh" ? "zh-CN" : "en";
  
  // 通知code.ts语言已变化
  parent.postMessage({ pluginMessage: { type: "change-language", lang: lang } }, "*");
  
  // 更新所有带有data-i18n属性的元素
  document.querySelectorAll("[data-i18n]").forEach(el => {
    const key = el.getAttribute("data-i18n");
    if (key) {
      el.textContent = t(key);
    }
  });
  
  // 更新语言按钮状态
  document.querySelectorAll(".lang-btn").forEach(btn => {
    const btnLang = btn.getAttribute("data-lang");
    if (btnLang === lang) {
      btn.classList.add("active");
    } else {
      btn.classList.remove("active");
    }
  });
  
  // 更新初始状态
  updateStatus(t("waitingSelection"), "info");
}

// 保存当前图片数据
let currentImageBytes: number[] | null = null;
let currentSvg: string | null = null;

try {
  const statusEl = document.getElementById("status");
  const statusTextEl = document.getElementById("status-text");
  const sourcePreviewImg = document.getElementById("original-preview") as HTMLImageElement;
  const sourceFileName = document.getElementById("file-name");
  const sourceMeta = document.getElementById("original-meta");
  const svgPreview = document.getElementById("svg-preview");
  const convertBtn = document.getElementById("convert");
  const copyBtn = document.getElementById("copy");
  const downloadBtn = document.getElementById("download");
  
  // 转换参数元素
  const qtresRange = document.getElementById("qtres") as HTMLInputElement;
  const pathomitRange = document.getElementById("pathomit") as HTMLInputElement;
  const rightangleenhanceCheckbox = document.getElementById("rightangleenhance") as HTMLInputElement;
  
  // 获取所有预设 radio 按钮
  const presetRadios = document.querySelectorAll('input[name="preset"]');

  console.log("[ui.ts] DOM elements loaded");

  // 状态图标 SVG
  const infoIcon = `<svg class="status-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 22C17.5228 22 22 17.5228 22 12C22 6.47715 17.5228 2 12 2C6.47715 2 2 6.47715 2 12C2 17.5228 6.47715 22 12 22Z" stroke="#667085" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
    <path d="M12 8V12L15 15" stroke="#667085" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
  </svg>`;
  
  const successIcon = `<svg class="status-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <circle cx="12" cy="12" r="10" fill="#86efac"/>
    <path d="M7 13L10 16L17 8" stroke="#166534" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
  </svg>`;
  
  const errorIcon = `<svg class="status-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <circle cx="12" cy="12" r="10" fill="#fda4af"/>
    <path d="M9 9L15 15M15 9L9 15" stroke="#be123c" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
  </svg>`;

  // 更新状态的函数
  function updateStatus(text: string, tone: string = "info") {
    if (statusTextEl) {
      statusTextEl.textContent = text;
    }
    if (statusEl) {
      statusEl.setAttribute("data-tone", tone);
      // 更新图标
      const iconHtml = tone === "success" ? successIcon : tone === "error" ? errorIcon : infoIcon;
      statusEl.innerHTML = iconHtml + `<span id="status-text">${text}</span>`;
    }
  }

  // 初始化语言
  updateLanguage("en");

  // 语言切换按钮事件
  document.querySelectorAll(".lang-btn").forEach(btn => {
    btn.addEventListener("click", () => {
      const lang = btn.getAttribute("data-lang");
      if (lang) {
        updateLanguage(lang);
      }
    });
  });

  // 防抖函数，避免频繁转换
  function debounce(func: Function, wait: number) {
    let timeout: NodeJS.Timeout;
    return function executedFunction(...args: any[]) {
      const later = () => {
        clearTimeout(timeout);
        func(...args);
      };
      clearTimeout(timeout);
      timeout = setTimeout(later, wait);
    };
  }

  // 转换函数
  async function convertImage() {
    if (!currentImageBytes) {
      return;
    }

    try {
      updateStatus(t("converting"), "info");

      // 1. 将字节加载到图片
      const img = new Image();
      const uint8Array = new Uint8Array(currentImageBytes);
      const blob = new Blob([uint8Array], { type: "image/png" });
      const objectUrl = URL.createObjectURL(blob);

      await new Promise((resolve, reject) => {
        img.onload = resolve;
        img.onerror = reject;
        img.src = objectUrl;
      });

      // 2. 绘制到 Canvas 获取 ImageData
      const canvas = document.createElement("canvas");
      canvas.width = img.naturalWidth;
      canvas.height = img.naturalHeight;
      const ctx = canvas.getContext("2d");
      if (!ctx) throw new Error("无法获取 canvas context");
      ctx.drawImage(img, 0, 0);
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

      // 3. 使用 imagetracerjs 转换，读取 UI 中的参数值
      const selectedPreset = Array.from(presetRadios).find(radio => radio.checked) as HTMLInputElement;
      const preset = selectedPreset?.value || "default";
      const qtres = parseFloat(qtresRange?.value || "1") / 10; // 0-100 → 0-10
      const pathomit = parseInt(pathomitRange?.value || "8");
      const rightangleenhance = rightangleenhanceCheckbox?.checked || false;
      
      console.log("[ui.ts] Conversion parameters:", {
        preset,
        qtres,
        pathomit,
        rightangleenhance
      });
      
      // 获取预设选项并覆盖自定义参数
      const options = ImageTracer.optionpresets[preset] || ImageTracer.optionpresets["default"];
      
      // 覆盖用户自定义参数
      options.qtres = qtres;
      options.pathomit = pathomit;
      options.rightangleenhance = rightangleenhance;
      
      console.log("[ui.ts] Final options:", options);
      
      currentSvg = ImageTracer.imagedataToSVG(imageData, options);

      // 4. 显示 SVG 预览，确保 SVG 正确适应预览区域
      if (svgPreview) {
        svgPreview.innerHTML = currentSvg;
        // 获取 SVG 元素并调整样式
        const svgElement = svgPreview.querySelector("svg");
        if (svgElement) {
          // 保存原始宽高
          const originalWidth = svgElement.getAttribute("width");
          const originalHeight = svgElement.getAttribute("height");
          
          // 确保 SVG 有 viewBox 属性
          if (!svgElement.hasAttribute("viewBox")) {
            const width = originalWidth || "100";
            const height = originalHeight || "100";
            svgElement.setAttribute("viewBox", `0 0 ${width} ${height}`);
          }
          
          // 移除固定宽度和高度，让 SVG 自适应
          svgElement.removeAttribute("width");
          svgElement.removeAttribute("height");
          
          // 设置 CSS 样式确保等比缩放
          svgElement.style.width = "100%";
          svgElement.style.height = "100%";
          svgElement.style.maxWidth = "100%";
          svgElement.style.maxHeight = "100%";
          svgElement.style.objectFit = "contain";
          svgElement.style.display = "block";
        }
      }

      // 5. 启用其他按钮
      if (copyBtn) copyBtn.disabled = false;
      if (downloadBtn) downloadBtn.disabled = false;

      updateStatus(t("conversionSuccess"), "success");

      URL.revokeObjectURL(objectUrl);
    } catch (error) {
      console.error("[ui.ts] Conversion error:", error);
      updateStatus(t("conversionError") + (error as Error).message, "error");
    }
  }

  // 防抖版本的转换函数
  const debouncedConvert = debounce(convertImage, 300);


  
  // 更新滑块进度条
  function updateSliderProgress(slider: HTMLInputElement) {
    const min = parseFloat(slider.min || "0");
    const max = parseFloat(slider.max || "100");
    const value = parseFloat(slider.value || "0");
    const progress = ((value - min) / (max - min)) * 100;
    slider.style.setProperty("--progress", `${progress}%`);
  }

  if (qtresRange) {
    updateSliderProgress(qtresRange);
    qtresRange.addEventListener("input", () => {
      const qtresValueEl = document.getElementById("qtres-value");
      if (qtresValueEl) qtresValueEl.textContent = qtresRange.value;
      updateSliderProgress(qtresRange);
      debouncedConvert();
    });
  }
  
  if (pathomitRange) {
    updateSliderProgress(pathomitRange);
    pathomitRange.addEventListener("input", () => {
      const pathomitValueEl = document.getElementById("pathomit-value");
      if (pathomitValueEl) pathomitValueEl.textContent = pathomitRange.value;
      updateSliderProgress(pathomitRange);
      debouncedConvert();
    });
  }
  
  // 增强直角边缘复选框变化时实时转换
  if (rightangleenhanceCheckbox) {
    rightangleenhanceCheckbox.addEventListener("change", debouncedConvert);
  }
  
  // 预设 radio 按钮变化时，更新滑块值并实时转换
  presetRadios.forEach(radio => {
    radio.addEventListener("change", () => {
      if (radio.checked) {
        const preset = radio.value;
        console.log("[ui.ts] Preset changed to:", preset);
        
        // 获取预设选项
        const presetOptions = ImageTracer.optionpresets[preset] || ImageTracer.optionpresets["default"];
        
        // 更新滑块值
        if (qtresRange) {
          const qtresValue = (presetOptions.qtres ?? 1) * 10; // 0-10 → 0-100
          qtresRange.value = qtresValue.toString();
          const qtresValueEl = document.getElementById("qtres-value");
          if (qtresValueEl) qtresValueEl.textContent = qtresValue.toString();
          updateSliderProgress(qtresRange);
        }
        
        if (pathomitRange) {
          pathomitRange.value = presetOptions.pathomit?.toString() || "8";
          const pathomitValueEl = document.getElementById("pathomit-value");
          if (pathomitValueEl) pathomitValueEl.textContent = presetOptions.pathomit?.toString() || "8";
          updateSliderProgress(pathomitRange);
        }
        
        if (rightangleenhanceCheckbox) {
          rightangleenhanceCheckbox.checked = presetOptions.rightangleenhance ?? true;
        }
        
        // 实时转换
        debouncedConvert();
      }
    });
  });

  // 复制 SVG 源码按钮点击事件
  if (copyBtn) {
    copyBtn.addEventListener("click", async () => {
      if (!currentSvg) {
        updateStatus(t("pleaseConvertFirst"), "error");
        return;
      }

      try {
        console.log("[ui.ts] Attempting to copy SVG to clipboard...");
        
        if (navigator.clipboard && navigator.clipboard.writeText) {
          try {
            await navigator.clipboard.writeText(currentSvg);
            console.log("[ui.ts] Copied using clipboard API");
            updateStatus(t("svgCopied"), "success");
            return;
          } catch (clipboardError) {
            console.log("[ui.ts] Clipboard API failed, falling back to textarea method");
          }
        }
        
        const textArea = document.createElement("textarea");
        textArea.value = currentSvg;
        textArea.style.position = "fixed";
        textArea.style.left = "-999999px";
        textArea.style.top = "-999999px";
        textArea.style.width = "2em";
        textArea.style.height = "2em";
        textArea.style.padding = "0";
        textArea.style.border = "none";
        textArea.style.outline = "none";
        textArea.style.boxShadow = "none";
        textArea.style.background = "transparent";
        document.body.appendChild(textArea);
        textArea.focus();
        textArea.select();
        
        try {
          const successful = document.execCommand("copy");
          if (successful) {
            console.log("[ui.ts] Copied using execCommand");
            updateStatus(t("svgCopied"), "success");
          } else {
            throw new Error("复制命令执行失败");
          }
        } finally {
          document.body.removeChild(textArea);
        }
      } catch (error) {
        console.error("[ui.ts] Copy error:", error);
        updateStatus(t("copyError") + (error as Error).message, "error");
      }
    });
  }

  // 导出 SVG 文件按钮点击事件
  if (downloadBtn) {
    downloadBtn.addEventListener("click", () => {
      if (!currentSvg) {
        updateStatus(t("pleaseConvertFirst"), "error");
        return;
      }

      try {
        const blob = new Blob([currentSvg], { type: "image/svg+xml" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = "converted-image.svg";
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);

        updateStatus(t("svgExported"), "success");
      } catch (error) {
        console.error("[ui.ts] Download error:", error);
        updateStatus(t("exportError") + (error as Error).message, "error");
      }
    });
  }

  window.onmessage = (event) => {
    console.log("[ui.ts] Received message from main:", event.data);
    const msg = event.data.pluginMessage;
    console.log("[ui.ts] pluginMessage:", msg);
    if (!msg) {
      console.log("[ui.ts] No pluginMessage found");
      return;
    }

    if (msg.type === "selection-checked") {
      console.log("[ui.ts] Handling selection-checked message");
      if (msg.error) {
        console.log("[ui.ts] Error message:", msg.error);
        currentImageBytes = null;
        currentSvg = null;
        updateStatus(msg.error, "error");
        if (copyBtn) copyBtn.disabled = true;
        if (downloadBtn) downloadBtn.disabled = true;
        if (svgPreview) svgPreview.innerHTML = "";
      } else {
        console.log("[ui.ts] Success message, data:", msg.data);
        updateStatus(t("selectionRead") + (msg.data?.nodeName || t("unknownNode")), "success");

        if (msg.data?.imageBytes) {
          currentImageBytes = msg.data.imageBytes;
          console.log("[ui.ts] Setting image preview from bytes, length:", currentImageBytes.length);
          if (sourcePreviewImg) {
            const uint8Array = new Uint8Array(currentImageBytes);
            const blob = new Blob([uint8Array], { type: "image/png" });
            const objectUrl = URL.createObjectURL(blob);
            sourcePreviewImg.src = objectUrl;
            sourcePreviewImg.style.display = "block";
          }

          if (sourceFileName && msg.data?.nodeName) {
            sourceFileName.textContent = msg.data.nodeName;
          }

          if (sourceMeta && msg.data?.width && msg.data?.height) {
            sourceMeta.textContent = `${Math.round(msg.data.width)} × ${Math.round(msg.data.height)}`;
          }

          // 自动转换为 SVG
          debouncedConvert();
        }
      }
    }
  };

  console.log("[ui.ts] Sending ui-ready...");
  parent.postMessage({ pluginMessage: { type: "ui-ready" } }, "*");
  // 同时发送初始语言
  parent.postMessage({ pluginMessage: { type: "change-language", lang: currentLang } }, "*");
  console.log("[ui.ts] ui-ready sent");

} catch (error) {
  console.error("[ui.ts] Error in UI script:", error);
  const statusEl = document.getElementById("status");
  const statusTextEl = document.getElementById("status-text");
  if (statusEl && statusTextEl) {
    // 简单更新，不调用 updateStatus，因为图标可能没有定义
    statusEl.setAttribute("data-tone", "error");
    // 快速设置图标和文本
    const errorIcon = `<svg class="status-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
      <path d="M12 22C17.5228 22 22 17.5228 22 12C22 6.47715 17.5228 2 12 2C6.47715 2 2 6.47715 2 12C2 17.5228 6.47715 22 12 22Z" fill="#fda4af"/>
      <path d="M15 9L9 15M9 9L15 15" stroke="#be123c" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
    </svg>`;
    statusEl.innerHTML = errorIcon + `<span id="status-text">UI 错误: ${(error as Error).message}</span>`;
  }
}
